spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.25 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.75) stage = 3;
    else if (progress >= 0.75) stage = 4;

    var midX = W / 2;
    var midY = H / 2 - 20;

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    if (stage === 1) {
      // Show 2^3
      ctx.font = 'bold 20px -apple-system, sans-serif';
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('2³', midX, midY - 20);

      ctx.font = '18px monospace';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('(2 × 2 × 2)', midX, midY + 15);
    } else if (stage === 2) {
      // Show 2^2
      ctx.font = 'bold 20px -apple-system, sans-serif';
      ctx.fillStyle = '#34D399';
      ctx.fillText('2²', midX, midY - 20);

      ctx.font = '18px monospace';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('(2 × 2)', midX, midY + 15);
    } else if (stage === 3) {
      // Show 2^3 * 2^2 expanded multiplication
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('2³ × 2²', midX, midY - 25);

      ctx.font = '16px monospace';
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('(2 × 2 × 2)', midX - 45, midY + 15);
      ctx.fillStyle = '#F3F4F6';
      ctx.fillText('×', midX, midY + 15);
      ctx.fillStyle = '#34D399';
      ctx.fillText('(2 × 2)', midX + 45, midY + 15);
    } else {
      // Combine into 2^5
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillStyle = '#10B981';
      ctx.fillText('2³ × 2² = 2³⁺² = 2⁵', midX, midY - 25);

      ctx.font = '18px monospace';
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('2 × 2 × 2 × 2 × 2 = 32', midX, midY + 15);
    }

    // Bottom text explanations
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('First Term: 2³', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('This equals 2 multiplied by itself 3 times.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillText('Second Term: 2²', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('This equals 2 multiplied by itself 2 times.', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillText('Combining the Multiplications', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('When multiplied, we join the groups of factors together.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Apply Product Rule: add the exponents!', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('3 factors + 2 factors = 5 factors of 2. 2⁵ = 32.', W / 2, H - 22);
    }
  }
};
